var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"唔……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"으엑윽!","JPN":"うげっ、うっ！","ENG":"Eeeck!","TWN":"啊啊啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"외지인님…!","JPN":"よそ者様……！","ENG":"Ms. Rivet...!","TWN":"外地人……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"조금만 더 힘내 주세요! 외지인님마저 당하시면 부학회장님 혼자 싸우셔야 하잖아요!","JPN":"もうちょっと頑張ってください！　よそ者様までやられてしまうと、副学会長様がお一人で戦わないといけないじゃないですか！","ENG":"You have to get up! If you are defeated, the Vice President will have to fight alone!","TWN":"再加把勁兒啊！如果連外地人都倒下了，那就得副學會長一個人戰鬥了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"우으. 까칠하게 생겨선 보통내기가 아니네. 호라이즌이랑 붙여도 되겠다.","JPN":"うう。冷たそうに見えてただものじゃないね。ホライズンと戦わせても大丈夫そう。","ENG":"Ngh... Guess you're strong as you look cold. You're right on par with Horizon.","TWN":"呃，長得這麼刻薄，可不是一般能打呢。或許和地平線都有得拼。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님이 잡히게 생겼는데 그런 말이 나오세요?!","JPN":"副学会長様が捕まるかもしれないのに、冗談はやめてください！！","ENG":"How can you say that when the Vice President's about to get captured?!","TWN":"副學會長就要被抓了，你還有閒心說這種話？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"너무 나쁘게 생각하지 마. 의식을 치러도 촉수만 좀 돋고 끝날 수도 있잖아.","JPN":"あんまり悪い方に考えるのやめようよ。儀式を行っても、触手が何本が生えるだけかもしれないじゃん？","ENG":"What's the worst that can happen? Even if she goes through with the ritual, she just might end up with a few tentacles, right?","TWN":"別想得太壞了，就算是舉行儀式，也有可能只是稍微長點觸手就結束了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"끔찍해요! 그런 일은 절대 안 된다고요!","JPN":"考えたくもありません！　そんなの絶対ダメです！","ENG":"That's terrible! You can't let that happen to her!","TWN":"好可怕！絕對不可以發生那種事！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"힘내세요, 부학회장님!","JPN":"頑張ってください、副学会長様！","ENG":"You can do it, ma'am!","TWN":"你加油，副學會長！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"……하.","JPN":"……は。","ENG":"*Sigh*","TWN":"……哈。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"저 애를 간병인으로 두셨다죠. 맥크레디 집안답게 취미가 참 고상하시군요.","JPN":"あの子を看病人にしたそうですね。マクレディー家らしく、とても上品な趣味ですね。","ENG":"She is your caregiver? What elegant taste the MacCready family has.","TWN":"你讓那孩子當看護了是嗎。不愧是麥克蕾蒂家族的人，真有閒情逸致。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"종교학부장이 학회에 떠도는 소문을 가르쳐 주던가요?","JPN":"宗教学部長から学会での噂話は聞きましたか？","ENG":"Did the Dean of Religion tell you about the rumors going around the Society?","TWN":"宗教學院院長告訴過你學會裡流傳的傳言嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그렇다면 저에 대한 인식 중 한 가지는 정정해야 할 겁니다.","JPN":"でしたら私に対する認識のうち、一つは訂正するべきでしょう。","ENG":"If so, one of your impressions of me must be corrected.","TWN":"那麼對我的認識中，有一點我必須要更正一下。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"법학부장에게 요구되는 조건들은 어디까지나 <color=#ffd34c>최소</color>예요.","JPN":"法学部長に要求される条件は、<color=#ffd34c>最低限</color>の意味です。","ENG":"The requirements of becoming Dean of Law are only the <color=#ffd34c>minimum</color>.","TWN":"法學院院長要求具備的條件，只是<color=#ffd34c>最低</color>標準。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"쿨럭……! 쿨럭……!","JPN":"ゲホッ……！　ゲホッ……！","ENG":"*Cough...!* *Cough!*","TWN":"咳咳……！咳咳……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"회동 때 분명히 잠자코 지내시라고 경고드렸습니다.","JPN":"会合の時、はっきりと大人しくしているよう警告したはずです。","ENG":"I warned you at the meeting to keep your head down.","TWN":"會議時我已經明確警告過你，讓你老實待著。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그걸 이해 못 하실 만큼 이해력이 부족하진 않으셨겠죠.","JPN":"それを理解できないほど、理解力が足りないわけではないでしょう。","ENG":"I'm sure you're competent enough to understand what that meant.","TWN":"連這都聽不懂，看來是你的理解能力不夠。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그런데 왜 이제 와서 학회장 자리를 탐내십니까? 권력이 아쉬워졌나요?","JPN":"なのに、どうして今更学会長の地位を欲がるのですか？　権力が欲しくなったのですか？","ENG":"But why the sudden change of heart? Do you miss having power?","TWN":"不過事到如今，你又為什麼想要學會長的位置了呢？是因為放不下權力嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"꼴사납군요. 너무 쉬워요.","JPN":"見苦しいですね。簡単すぎます。","ENG":"Pathetic. This is too easy.","TWN":"樣子真狼狽啊，太簡單了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"이래서야 제가─","JPN":"これでは、私が……","ENG":"This is why I t–","TWN":"這樣我就不能——"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"읏?! 모래……!?","JPN":"うっ？！　砂……！？","ENG":"Ngh?! Sand...?!","TWN":"呃？！沙子……！？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……나름대로 꾀를 썼는데 역시 통하지 않네요. 좀 더 끌어들여야 했어요.","JPN":"……私なりに機転をきかせたつもりでしたが、やはり通じませんわね。もっと引きつけるべきでした。","ENG":"…It seems my trick didn't work on you. Maybe I should have brought you in closer.","TWN":"……我耍了點小手段，果然行不通呢。距離再拉近點就好了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"수치심을 감수하고 기습해서 겨우 펜던트 하나 베다니……. 응?","JPN":"恥を忍んで奇襲したのに、得たのがたかがペンダント一つなんて……うん？","ENG":"I endured all that shame just to get your pendant...? Hmm?","TWN":"我是忍著羞恥心突襲的，結果卻只砍到了一個吊墜……嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"내놔!!","JPN":"返せ！！","ENG":"Give that back!","TWN":"還給我！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"으윽!","JPN":"ううっ！","ENG":"Argh!","TWN":"呃啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님!","JPN":"副学会長様！","ENG":"Ms. Vice President!","TWN":"副學會長！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"어떡해…. 온몸이 상처 투성이에요.","JPN":"どうしよう……全身傷だらけです。","ENG":"Oh no... You're covered in wounds...","TWN":"怎麼辦……你渾身都是傷。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 더 이상은 위험해요. 지금이라도 저희 법학부를 따라가요, 네?","JPN":"副学会長様、これ以上は危険です。今からでも法学部に大人しく付いて行きましょう、ね？","ENG":"You can't do this anymore. Let's just do as she says, okay?","TWN":"副學會長，再這樣下去你就危險了。現在你就跟著法學院走吧，好不好？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"실키…….","JPN":"シルキー……","ENG":"Sylkie...","TWN":"思琪……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"네? 부학회장님, 왜…… 왜 그러세요?","JPN":"はい？　副学会長様、ど……どうしました？","ENG":"Huh? W-what are you doing... Ms. Vice President?","TWN":"嗯？副學會長，怎麼了……出什麼事了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"아, 안 돼…!","JPN":"だ、ダメ……！","ENG":"N-no...!","TWN":"不…不行……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"법학부장님……. 이러지 마세요. 부학회장님은 아무 잘못 없어요.","JPN":"法学部長様……おやめください。副学会長様は何も悪くないんです。","ENG":"Please... Don't do this. She did nothing wrong.","TWN":"法學院院長……請不要這樣。副學會長什麼錯都沒有。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"사실은 알고 계시잖아요. 착하고 친절한 분이에요.","JPN":"本当はご存じですよね？　優しくて親切な方なんです。","ENG":"You know what she's like. She's a good and kind person.","TWN":"其實你也知道不是嘛。她是個善良、親切的人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"주민은 비켜 있어라. 이건 학회의 일이야.","JPN":"住民は下がっていろ。これは学会のことだ。","ENG":"Move aside, resident. This is Society matters.","TWN":"居民請讓開，這是學會的事。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"하, 하지만…!","JPN":"で、でも……！","ENG":"B-but...!","TWN":"可…可是……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"실키, 괜찮아요. 대화는 언제나 환영합니다.","JPN":"シルキー、大丈夫ですわ。対話ならいつでも歓迎です。","ENG":"Sylkie, it is okay. I would rather exchange words than swords.","TWN":"思琪，沒關係的。這種對話，我隨時歡迎。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님. 신중하게 답해 주십시오.","JPN":"副学会長。慎重にお答えください。","ENG":"Ms. Vice President. I urge you to answer carefully.","TWN":"副學會長，請慎重地回答我。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"보셨습니까?","JPN":"見ましたか？","ENG":"Did you see it?","TWN":"你看見了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……네.","JPN":"……はい。","ENG":"...Yes.","TWN":"……是的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"*Sigh...*","TWN":"呼……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그렇다면 처벌에 사적인 감정이 개입됐다고 주장할 여지가 남겠군요.","JPN":"でしたら処罰に私的な感情が入っていると主張する余地がありますね。","ENG":"That means you could claim that my punishment of you was motivated by personal feelings.","TWN":"那麼你就有了主張我的處罰摻雜了私人感情的理由呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"당신에 대해서는 죽이거나, 믿어 보거나. 둘 중 하나니까요.","JPN":"あなたについては殺すか、信じてみるか。どちらかですから。","ENG":"So now, my choices would be to either kill you, or believe you.","TWN":"因為對於你，要麼殺了，要麼相信，就只有這二者之一。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"집요한 태도는 인정해 드리겠습니다.","JPN":"粘り強い態度は認めてあげます。","ENG":"For that, I applaud your persistence.","TWN":"我認可你執著的態度。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"법학부장, 당신…….","JPN":"法学部長、あなた……","ENG":"Dean of Law, you...","TWN":"法學院院長，你……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"하지만 그렇게까지 해서 뭘 이루고 싶으신 거죠?","JPN":"ですが、そこまでして何がしたいのですか？","ENG":"But what is it that you wish to achieve?","TWN":"只是做了這麼多，你到底是要實現什麼呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"일전에 말씀드린 대로, 학회장이 되어 학회의 기조를 바꾸려는 겁니까?","JPN":"この前お話ししたように、学会長になって学会の根底から変えるおつもりですか？","ENG":"Are you trying to become President just to change the very nature of the Society?","TWN":"就像之前說的那樣，你是想成為學會長，然後改變學會的基調嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 이전까지는 그랬지만 생각을 바꿨어요.","JPN":"いいえ。以前はそうでしたが、考えが変わりました。","ENG":"No. I did, but I have changed my mind.","TWN":"不，之前是那樣的，但是現在我改變想法了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"학회를……","JPN":"学会を……","ENG":"The Society...","TWN":"我要把學會……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"지식의 호수를, 손에 넣을 겁니다.","JPN":"知識の湖を、手に入れますわ。","ENG":"And the Lake of Knowledge... I will make them mine.","TWN":"把知識湖水，拿到手。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};